const item = $('Deficiency Details').first();
const bin = item.binary || {};
const keys = Object.keys(bin);
if (keys.length === 0) {
  return [{ json: { isPhoto: false } }];
}
const prefix = 'INSP_' + new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);
return keys.map((k, i) => ({
  json: { isPhoto: true, uploadName: prefix + '_' + (i + 1) + '_' + (bin[k].fileName || ('photo' + (i + 1) + '.jpg')) },
  binary: { data: bin[k] }
}));

let uploads = [];
try { uploads = $('Upload Photo to OneDrive').all(); } catch (e) { uploads = []; }
const links = uploads.map(u => (u.json && (u.json.webUrl || u.json.webURL)) || '').filter(Boolean);
const p1 = $('On form submission').first().json;
const p2 = $('Deficiency Details').first().json;
const p3 = $('Risk Evaluation').first().json;
let rev = {};
try { rev = $('Review & Confirm').first().json; } catch (e) { rev = {}; }
const merged = { ...p1, ...p2, ...p3, ...rev };
const photosField = p2.Photos !== undefined ? p2.Photos : undefined;
const attachedCount = Array.isArray(photosField) ? photosField.length : (photosField ? 1 : 0);
return [{ json: { ...merged, photoLinks: links.join(', '), photosAttached: attachedCount > 0 } }];

const item = $input.first().json;
const errors = [];

if (!item.site?.trim()) errors.push('Site is required');
if (!item.parentAsset?.trim()) errors.push('Parent Asset is required');
if (!item.inspectionDate?.trim()) errors.push('Inspection Date is required');
if (!item.inspectorName?.trim()) errors.push('Inspector Name is required');
if (!item.priorityRating?.trim()) errors.push('Priority Rating is required');
if (!item.recommendedAction?.trim()) errors.push('Recommended Action is required');

const priority = (item.priorityRating || '').trim().toUpperCase();
const validPriorities = ['P1','P2','P3','P4','P5'];
if (priority && !validPriorities.includes(priority)) {
  errors.push('Priority Rating must be P1-P5 — received: ' + priority);
}

const isCritical = ['P1','P2'].includes(priority);
const hasPhotos = !!(item.photoLinks || '').trim();
const photosProvided = item.photosAttached === true || hasPhotos;
const hasDeficiency = !!(item.deficiencyCategory || '').trim();

if (isCritical && !photosProvided) {
  errors.push('At least one photo is required for P1 and P2 (critical) findings');
}

return [{
  json: {
    ...item,
    priorityRating: priority || item.priorityRating,
    validationPassed: errors.length === 0,
    validationErrors: errors,
    isCritical,
    hasPhotos,
    photosProvided,
    hasDeficiency,
    submittedAt: new Date().toISOString(),
  }
}];

const registryData = $input.first().json;
const form = $('Validate and Enrich').first().json;

const rows = (registryData.values || []);
const SITE_COL = 0;
const PARENT_COL = 1;
const ASSETID_COL = 2;

const normalize = (s) => String(s || '').trim().toLowerCase();
const formSite = normalize(form.site);
const formParent = normalize(form.parentAsset);
const formAssetId = normalize(form.assetId);

const siteFound = rows.some(r => normalize(r[SITE_COL]) === formSite);
const assetIdMatch = formAssetId !== '' && rows.some(r => normalize(r[ASSETID_COL]) === formAssetId);
const parentAssetMatch = formParent !== '' && rows.some(r => normalize(r[SITE_COL]) === formSite && normalize(r[PARENT_COL]) === formParent);

const assetFound = assetIdMatch || parentAssetMatch;
const assetValid = siteFound && assetFound;

return [{
  json: {
    ...form,
    siteFound,
    assetIdMatch,
    parentAssetMatch,
    assetFound,
    assetValid,
  }
}];

const rangeInfo = $input.first().json;
const form = $('Check Asset in Registry').first().json;

const values = rangeInfo.values || [];
const INSPECTOR_COL = 6;
let targetRow = null;
for (let i = 3; i < values.length; i++) {
  const insp = values[i] && values[i][INSPECTOR_COL];
  if (insp === null || insp === undefined || String(insp).trim() === '') { targetRow = i + 1; break; }
}
if (targetRow === null) targetRow = (values.length || 3) + 1;
const nextRow = targetRow;

const priorityDescriptions = {
  P1: 'Critical Condition - Immediate action required; repair within 60 days max',
  P2: 'Poor Condition - Repair actions needed within 12 months',
  P3: 'Bad Condition - Repairs needed within 24 to 36 months',
  P4: 'Fair Condition - Monitor before next scheduled inspection',
  P5: 'Good Condition - No repairs required',
};
const priority = (form.priorityRating || '').toUpperCase();
const priorityDescription = priorityDescriptions[priority] || '';
const immediateNotification = ['P1','P2'].includes(priority) ? 'Yes' : 'No';

const consMatch = String(form.consequenceSeverity || '').match(/[1-5]/);
const cons = consMatch ? consMatch[0] : '';
const likeMatch = String(form.likelihood || '').match(/[A-Ea-e]/);
const like = likeMatch ? likeMatch[0].toUpperCase() : '';
const grid = {
  '5': { A:25, B:24, C:22, D:19, E:15 },
  '4': { A:23, B:21, C:18, D:14, E:10 },
  '3': { A:20, B:17, C:13, D:9, E:6 },
  '2': { A:16, B:12, C:8, D:5, E:3 },
  '1': { A:11, B:7, C:4, D:2, E:1 },
};
const riskRank = (grid[cons] && grid[cons][like] !== undefined) ? grid[cons][like] : '';
const riskRating = riskRank === '' ? '' : (riskRank >= 17 ? 'High' : (riskRank >= 7 ? 'Medium' : 'Low'));

const stamp = new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);
const recordId = (form.assetFound ? 'INSP-' : 'REVIEW-') + stamp;
const assetId = (form.assetId && String(form.assetId).trim()) ? form.assetId : 'No ID Yet';
const baseFocus = form.focusArea || '';
const focusArea = form.assetFound ? baseFocus : ((baseFocus ? baseFocus + ' | ' : '') + 'ASSET NOT IN REGISTRY - pending verification');

const rowValues = [[
  recordId,
  form.site,
  assetId,
  form.parentAsset,
  form.category || '',
  form.inspectionDate,
  form.inspectorName,
  form.ppeRequirementsMet,
  form.componentType,
  form.subComponent || '',
  form.deficiencyCategory,
  form.detailedDescription,
  form.mechanisms || '',
  form.vibrationPresent || '',
  form.consequenceSeverity || '',
  form.mostAffectedConsequence || '',
  form.priorityRating,
  priorityDescription,
  form.recommendedAction,
  immediateNotification,
  form.furtherInvestigationRequired,
  form.ndtRequired,
  focusArea,
  form.likelihood || '',
  riskRank,
  riskRating,
]];

return [{
  json: {
    ...form,
    recordId,
    riskRank,
    riskRating,
    nextRow,
    inspectionsWriteRange: 'A' + nextRow + ':Z' + nextRow,
    rowValues,
  }
}];

const rangeInfo = $input.first().json;
const rec = $('Build Excel Row Data').first().json;
const values = rangeInfo.values || [];
const RECID_COL = 0;
let targetRow = null;
for (let i = 3; i < values.length; i++) {
  const v = values[i] && values[i][RECID_COL];
  if (v === null || v === undefined || String(v).trim() === '') { targetRow = i + 1; break; }
}
if (targetRow === null) targetRow = (values.length || 3) + 1;
const desc = 'Inspection photo(s) - ' + (rec.deficiencyCategory || '');
const rowValues = [[ rec.recordId, rec.site, rec.assetId, rec.parentAsset, rec.inspectionDate, rec.inspectorName, desc, rec.photoLinks ]];
return [{ json: { photoWriteRange: 'A' + targetRow + ':H' + targetRow, rowValues } }];

const category = ($('On form submission').first().json.category || '').trim();
const norm = (s) => String(s == null ? '' : s).trim();
const rows = ($input.first().json.values || []);
const sel = rows.filter(r => norm(r[0]).toLowerCase() === category.toLowerCase() && norm(r[6]) !== '');
const uniq = (idx, excl) => {
  const out = []; const seen = new Set();
  for (const r of sel) { const v = norm(r[idx]); if (!v || excl.includes(v) || seen.has(v)) continue; seen.add(v); out.push(v); }
  return out;
};
const opt = (arr) => ({ values: arr.map(o => ({ option: o })) });
const yn = { values: [{ option: 'Yes' }, { option: 'No' }] };
const formDefinition = [
  { fieldName: 'componentType', fieldLabel: 'Component', fieldType: 'dropdown', requiredField: true, fieldOptions: opt(uniq(2, ['ALL'])) },
  { fieldName: 'subComponent', fieldLabel: 'Sub-Component', fieldType: 'dropdown', requiredField: false, fieldOptions: opt(uniq(3, ['None','ALL'])) },
  { fieldName: 'focusArea', fieldLabel: 'Focus Area', fieldType: 'dropdown', requiredField: false, fieldOptions: opt(uniq(4, ['None'])) },
  { fieldName: 'deficiencyCategory', fieldLabel: 'Deficiency Category', fieldType: 'dropdown', requiredField: true, fieldOptions: opt(uniq(5, [])) },
  { fieldName: 'mechanisms', fieldLabel: 'Potential Failure Mechanism', fieldType: 'text', requiredField: false, placeholder: 'e.g. Shrinkage / aging' },
  { fieldName: 'detailedDescription', fieldLabel: 'Detailed Description (Indications)', fieldType: 'dropdown', requiredField: true, fieldOptions: opt(uniq(6, [])) },
  { fieldName: 'vibrationPresent', fieldLabel: 'Vibration Present', fieldType: 'dropdown', requiredField: true, fieldOptions: yn },
  { fieldName: 'furtherInvestigationRequired', fieldLabel: 'Further Investigation Required', fieldType: 'dropdown', requiredField: true, fieldOptions: yn },
  { fieldName: 'ndtRequired', fieldLabel: 'NDT Required', fieldType: 'dropdown', requiredField: true, fieldOptions: yn },
  { fieldName: 'Photos', fieldLabel: 'Site Photos (add up to 5; required for P1/P2 findings)', fieldType: 'file', requiredField: false, multipleFiles: true, acceptFileTypes: '.jpg,.jpeg,.png,.heic,.webp' }
];
return [{ json: { category, formDefinition } }];

const reg = $('Read Asset Registry from Excel').first().json;
const form = $('Check Asset in Registry').first().json;
const values = reg.values || [];
const SITE_COL = 0;
let targetRow = null;
for (let i = 3; i < values.length; i++) {
  const v = values[i] && values[i][SITE_COL];
  if (v === null || v === undefined || String(v).trim() === '') { targetRow = i + 1; break; }
}
if (targetRow === null) targetRow = (values.length || 3) + 1;
const assetId = (form.assetId && String(form.assetId).trim()) ? form.assetId : 'No ID Yet';
const rowValues = [[ form.site, form.parentAsset, assetId ]];
return [{ json: { registryWriteRange: 'A' + targetRow + ':C' + targetRow, rowValues } }];
